function phase1RenderContracts(){phase1EnsureState();const list=Array.isArray(S.ventes.contracts)?S.ventes.contracts:[];document.getElementById('main').innerHTML=`<div class="topbar"><h1>Contrats</h1></div>${phase1PageNoticeHtml()}<div class="kpis"><div class="kpi"><label>Contrats suivis</label><div class="v">${list.length}</div><small>base synchronisée</small></div><div class="kpi"><label>Actifs</label><div class="v vert">${list.filter(contract=>(contract.status||'').toLowerCase()==='actif').length}</div><small>sur la base actuelle</small></div></div>${list.length?`<div class="card phase1-table-wrap" style="padding:0"><table class="phase1-table"><tr><th>N°</th><th>Client</th><th>Nom</th><th>Début</th><th>Fin</th><th>Montant</th><th>Statut</th></tr>${list.map(contract=>`<tr><td class="phase1-mono">${esc(contract.numero||'—')}</td><td>${esc(contract.client||'—')}</td><td>${esc(contract.name||'Contrat')}</td><td class="phase1-mono">${fmtD(contract.startDate)}</td><td class="phase1-mono">${fmtD(contract.endDate)}</td><td class="num">${eur(Number(contract.amount)||0)}</td><td>${esc(contract.status||'Brouillon')}</td></tr>`).join('')}</table></div>`:`<div class="phase1-empty"><b>Aucun contrat dans la structure actuelle.</b><span>Cette page est prête pour la phase 4 et affichera les contrats dès qu'ils seront enregistrés dans Piloz.</span></div>`}`;}
function phase1RenderCatalog(){phase1EnsureState();const list=Array.isArray(S.ventes.catalog)?S.ventes.catalog:[];document.getElementById('main').innerHTML=`<div class="topbar"><h1>Articles & services</h1></div>${phase1PageNoticeHtml()}<div class="kpis"><div class="kpi"><label>Éléments disponibles</label><div class="v">${list.length}</div><small>catalogue synchronisé</small></div></div>${list.length?`<div class="card phase1-table-wrap" style="padding:0"><table class="phase1-table"><tr><th>Type</th><th>Référence</th><th>Nom</th><th>Prix HT</th><th>TVA</th><th>Actif</th></tr>${list.map(item=>`<tr><td>${esc(item.type||'—')}</td><td class="phase1-mono">${esc(item.reference||'—')}</td><td>${esc(item.name||'—')}</td><td class="num">${eur(Number(item.salePrice)||0)}</td><td class="num">${Number(item.taxRate)||0} %</td><td>${item.active===false?'Archivé':'Actif'}</td></tr>`).join('')}</table></div>`:`<div class="phase1-empty"><b>Catalogue vide pour le moment.</b><span>La structure est prête et s'appuie déjà sur l'état cloud. L'édition complète arrive en phase 2.</span></div>`}`;}
function phase1RenderDueDates(){phase1EnsureState();const list=phase1BuildDueDates(),late=list.filter(item=>item.status==='En retard').length;document.getElementById('main').innerHTML=`<div class="topbar"><h1>Échéances clients</h1></div>${phase1PageNoticeHtml()}<div class="kpis"><div class="kpi"><label>Échéances visibles</label><div class="v">${list.length}</div><small>factures et contrats</small></div><div class="kpi"><label>En retard</label><div class="v ${late?'rouge':''}">${late}</div><small>sur les données actuelles</small></div></div>${list.length?`<div class="card phase1-table-wrap" style="padding:0"><table class="phase1-table"><tr><th>Source</th><th>Client</th><th>Document</th><th>N°</th><th>Échéance</th><th>Montant</th><th>Payé</th><th>Reste</th><th>Jours</th><th>Statut</th></tr>${list.map(item=>`<tr><td>${item.source==='facture'?'Facture':'Contrat'}</td><td>${esc(item.client)}</td><td class="wide">${esc(item.document)}</td><td class="phase1-mono">${esc(item.reference)}</td><td class="phase1-mono">${fmtD(item.dueDate)}</td><td class="num">${eur(Math.round(item.amount*100)/100)}</td><td class="num">${eur(Math.round(item.paid*100)/100)}</td><td class="num">${eur(Math.round(item.remaining*100)/100)}</td><td class="num">${item.delta===null?'—':item.delta}</td><td><span class="phase1-status ${item.status==='En retard'?'danger':(item.status==='Réglée'?'ok':'warn')}">${esc(item.status)}</span></td></tr>`).join('')}</table></div>`:`<div class="phase1-empty"><b>Aucune échéance à afficher.</b><span>Les factures avec date d'échéance et les contrats avec date de fin remonteront ici automatiquement.</span></div>`}`;}
function phase1Matches(search,keywords){if(!search)return true;return keywords.join(' ').toLowerCase().includes(search.toLowerCase());}
function phase1Options(list,current){return list.map(value=>`<option value="${esc(value)}" ${current===value?'selected':''}>${esc(value)}</option>`).join('');}
function phase1BooleanOptions(current){return `<option value="">Choisir</option><option value="true" ${current===true?'selected':''}>Oui</option><option value="false" ${current===false?'selected':''}>Non</option>`;}
function phase1SetEntreprise(path,value,save){phase1EnsureState();const parts=path.split('.');let target=S.entreprise;while(parts.length>1)target=target[parts.shift()];target[parts[0]]=value;if(path==='fiscality.subjectToVat'&&value===false)S.entreprise.fiscality.vatNumber='';phase1SyncLegacyCompany();S.ventes.dueDates=phase1BuildDueDates();if(save)sauver('Paramètres entreprise enregistrés');}
function phase1SetEntrepriseChoice(path,raw,save){if(raw==='')return phase1SetEntreprise(path,null,save);if(raw==='true')return phase1SetEntreprise(path,true,save);if(raw==='false')return phase1SetEntreprise(path,false,save);phase1SetEntreprise(path,raw,save);}
function phase1ToggleAcceptedMethod(method,checked){phase1EnsureState();const list=Array.isArray(S.entreprise.banking.acceptedPaymentMethods)?S.entreprise.banking.acceptedPaymentMethods:[];if(checked&&!list.includes(method))list.push(method);S.entreprise.banking.acceptedPaymentMethods=checked?list:list.filter(item=>item!==method);sauver('Paramètres entreprise enregistrés');}
function phase1SetSettingsSection(section){phase1SettingsSection=section;render();}
function phase1UpdateSettingsSearch(value){phase1SettingsSearch=value;render();}
function phase1SettingsButton(id,label){return `<button class="${phase1SettingsSection===id?'on':''}" onclick="phase1SetSettingsSection('${id}')">${label}</button>`;}
function phase1RenderCompanySettings(){const e=S.entreprise,search=phase1SettingsSearch,sections=[];if(phase1Matches(search,['identité entreprise siret email téléphone adresse']))sections.push(`<div class="phase1-card"><h2>Identité</h2><div class="phase1-grid"><div class="phase1-field"><label>Raison sociale *</label><input value="${esc(e.identity.legalName)}" onchange="phase1SetEntreprise('identity.legalName',this.value,true)"></div><div class="phase1-field"><label>Nom commercial</label><input value="${esc(e.identity.tradeName)}" onchange="phase1SetEntreprise('identity.tradeName',this.value,true)"></div><div class="phase1-field"><label>Nom du responsable</label><input value="${esc(e.identity.ownerName)}" onchange="phase1SetEntreprise('identity.ownerName',this.value,true)"></div><div class="phase1-field"><label>Forme juridique *</label><input value="${esc(e.identity.legalForm)}" onchange="phase1SetEntreprise('identity.legalForm',this.value,true)"></div><div class="phase1-field"><label>SIRET *</label><input value="${esc(e.identity.siret)}" onchange="phase1SetEntreprise('identity.siret',this.value.replace(/\s+/g,''),true)"></div><div class="phase1-field"><label>Code APE / NAF</label><input value="${esc(e.identity.apeCode)}" onchange="phase1SetEntreprise('identity.apeCode',this.value,true)"></div><div class="phase1-field full"><label>Adresse *</label><input value="${esc(e.identity.addressLine1)}" onchange="phase1SetEntreprise('identity.addressLine1',this.value,true)"></div><div class="phase1-field"><label>Code postal *</label><input value="${esc(e.identity.postalCode)}" onchange="phase1SetEntreprise('identity.postalCode',this.value,true)"></div><div class="phase1-field"><label>Ville *</label><input value="${esc(e.identity.city)}" onchange="phase1SetEntreprise('identity.city',this.value,true)"></div><div class="phase1-field"><label>Pays *</label><input value="${esc(e.identity.country)}" onchange="phase1SetEntreprise('identity.country',this.value,true)"></div><div class="phase1-field"><label>Téléphone *</label><input value="${esc(e.identity.phone)}" onchange="phase1SetEntreprise('identity.phone',this.value,true)"></div><div class="phase1-field"><label>Email *</label><input type="email" value="${esc(e.identity.email)}" onchange="phase1SetEntreprise('identity.email',this.value,true)"></div></div></div>`);if(phase1Matches(search,['fiscalité tva devise langue']))sections.push(`<div class="phase1-card"><h2>Fiscalité</h2><div class="phase1-grid"><div class="phase1-field"><label>Assujetti à la TVA *</label><select onchange="phase1SetEntrepriseChoice('fiscality.subjectToVat',this.value,true)">${phase1BooleanOptions(e.fiscality.subjectToVat)}</select></div><div class="phase1-field"><label>Régime de TVA</label><input value="${esc(e.fiscality.vatRegime)}" onchange="phase1SetEntreprise('fiscality.vatRegime',this.value,true)"></div><div class="phase1-field"><label>N° TVA intracom</label><input value="${esc(e.fiscality.vatNumber)}" onchange="phase1SetEntreprise('fiscality.vatNumber',this.value,true)"></div><div class="phase1-field"><label>Taux de TVA par défaut *</label><input type="number" value="${Number(e.fiscality.defaultVatRate)||20}" onchange="phase1SetEntreprise('fiscality.defaultVatRate',Number(this.value),true)"></div><div class="phase1-field"><label>Devise *</label><input value="${esc(e.fiscality.currency)}" onchange="phase1SetEntreprise('fiscality.currency',this.value.toUpperCase(),true)"></div><div class="phase1-field"><label>Langue principale *</label><select onchange="phase1SetEntreprise('fiscality.language',this.value,true)"><option value="fr" ${e.fiscality.language==='fr'?'selected':''}>Français</option><option value="en" ${e.fiscality.language==='en'?'selected':''}>Anglais</option></select></div></div></div>`);if(phase1Matches(search,['banque iban bic paiements']))sections.push(`<div class="phase1-card"><h2>Banque & paiements</h2><div class="phase1-grid"><div class="phase1-field"><label>Titulaire du compte</label><input value="${esc(e.banking.accountHolder)}" onchange="phase1SetEntreprise('banking.accountHolder',this.value,true)"></div><div class="phase1-field"><label>Banque</label><input value="${esc(e.banking.bankName)}" onchange="phase1SetEntreprise('banking.bankName',this.value,true)"></div><div class="phase1-field"><label>IBAN</label><input value="${esc(e.banking.iban)}" onchange="phase1SetEntreprise('banking.iban',this.value.replace(/\s+/g,''),true)"></div><div class="phase1-field"><label>BIC</label><input value="${esc(e.banking.bic)}" onchange="phase1SetEntreprise('banking.bic',this.value.replace(/\s+/g,''),true)"></div><div class="phase1-field full"><label>Moyens de paiement acceptés</label><div class="phase1-checks">${phase1PaymentMethods.map(method=>`<label class="phase1-check"><input type="checkbox" ${e.banking.acceptedPaymentMethods.includes(method)?'checked':''} onchange="phase1ToggleAcceptedMethod('${esc(method)}',this.checked)"><span>${esc(method)}</span></label>`).join('')}</div></div><div class="phase1-field full"><label>Coordonnées bancaires disponibles plus tard</label><select onchange="phase1SetEntrepriseChoice('banking.remindLater',this.value,true)">${phase1BooleanOptions(e.banking.remindLater)}</select></div></div></div>`);return sections.length?sections.join(''):`<div class="phase1-card"><div class="phase1-section-empty">Aucun réglage ne correspond à votre recherche.</div></div>`;}
function phase1RenderDocumentSettings(){const e=S.entreprise,search=phase1SettingsSearch,sections=[];if(phase1Matches(search,['numérotation devis factures avoirs préfixe']))sections.push(`<div class="phase1-card"><h2>Numérotation</h2><div class="phase1-grid"><div class="phase1-field"><label>Préfixe devis *</label><input value="${esc(e.documents.quotePrefix)}" onchange="phase1SetEntreprise('documents.quotePrefix',this.value.toUpperCase(),true)"></div><div class="phase1-field"><label>Prochain devis *</label><input type="number" value="${Number(e.documents.quoteNextNumber)||1}" onchange="phase1SetEntreprise('documents.quoteNextNumber',Number(this.value),true)"></div><div class="phase1-field"><label>Préfixe factures *</label><input value="${esc(e.documents.invoicePrefix)}" onchange="phase1SetEntreprise('documents.invoicePrefix',this.value.toUpperCase(),true)"></div><div class="phase1-field"><label>Prochaine facture *</label><input type="number" value="${Number(e.documents.invoiceNextNumber)||1}" onchange="phase1SetEntreprise('documents.invoiceNextNumber',Number(this.value),true)"></div><div class="phase1-field"><label>Préfixe avoirs *</label><input value="${esc(e.documents.creditPrefix)}" onchange="phase1SetEntreprise('documents.creditPrefix',this.value.toUpperCase(),true)"></div><div class="phase1-field"><label>Prochain avoir *</label><input type="number" value="${Number(e.documents.creditNextNumber)||1}" onchange="phase1SetEntreprise('documents.creditNextNumber',Number(this.value),true)"></div></div><p class="phase1-note">Prévisualisations : <span class="phase1-mono">${esc(phase1DocNumber('D'))}</span> · <span class="phase1-mono">${esc(phase1DocNumber('F'))}</span></p></div>`);if(phase1Matches(search,['conditions paiement validité mentions']))sections.push(`<div class="phase1-card"><h2>Conditions documentaires</h2><div class="phase1-grid"><div class="phase1-field"><label>Conditions de paiement *</label><select onchange="phase1SetEntreprise('documents.defaultPaymentTerms',this.value,true)">${phase1Options(phase1PaymentTerms,e.documents.defaultPaymentTerms)}</select></div><div class="phase1-field"><label>Mode de paiement préféré *</label><select onchange="phase1SetEntreprise('documents.defaultPaymentMethod',this.value,true)">${phase1Options(phase1PaymentMethods,e.documents.defaultPaymentMethod)}</select></div><div class="phase1-field"><label>Validité des devis *</label><input type="number" value="${Number(e.documents.quoteValidityDays)||30}" onchange="phase1SetEntreprise('documents.quoteValidityDays',Number(this.value),true)"></div><div class="phase1-field"><label>Mention visible</label><input value="${esc(e.documents.visibleMention)}" onchange="phase1SetEntreprise('documents.visibleMention',this.value,true)"></div><div class="phase1-field full"><label>Pénalités de retard</label><textarea onchange="phase1SetEntreprise('documents.legalNotice',this.value,true)">${esc(e.documents.legalNotice)}</textarea></div><div class="phase1-field full"><label>Indemnité forfaitaire</label><textarea onchange="phase1SetEntreprise('documents.collectionFeeNotice',this.value,true)">${esc(e.documents.collectionFeeNotice)}</textarea></div></div></div>`);return sections.length?sections.join(''):`<div class="phase1-card"><div class="phase1-section-empty">Aucun réglage ne correspond à votre recherche.</div></div>`;}
function phase1RenderPipelineSettings(){if(!phase1Matches(phase1SettingsSearch,['pipeline probabilité relance cadence']))return`<div class="phase1-card"><div class="phase1-section-empty">Aucun réglage ne correspond à votre recherche.</div></div>`;return`<div class="phase1-card"><h2>Probabilités & relances</h2><div class="phase1-grid">${STATUTS_ENCOURS.map(status=>`<div class="phase1-field"><label>Probabilité – ${esc(status)}</label><input type="number" min="0" max="100" value="${S.params.probas[status]||0}" onchange="S.params.probas['${status}']=Number(this.value)||0;sauver('Probabilités enregistrées')"></div>`).join('')}${[['premiere','1ère relance'],['repondeur','Après répondeur'],['discussion','Après discussion'],['positif','Après contact positif'],['standard','Cadence standard']].map(([key,label])=>`<div class="phase1-field"><label>${label}</label><input type="number" min="0" max="60" value="${S.params.relance[key]||0}" onchange="S.params.relance['${key}']=Number(this.value)||0;sauver('Cadence enregistrée')"></div>`).join('')}</div></div>`;}
function phase1RenderSecuritySettings(){const search=phase1SettingsSearch,sections=[];if(phase1Matches(search,['compte session sécurité']))sections.push(`<div class="phase1-card"><h2>Compte</h2><p>Utilisateur connecté : <b>${esc((SES&&SES.email)||'mode local')}</b></p><div class="actions"><button class="btn btn-o" onclick="deconnecter()">Se déconnecter</button></div></div>`);if(phase1Matches(search,['notifications pin']))sections.push(`<div class="phase1-card"><h2>Notifications & verrouillage</h2><div class="actions">${S.notif?'<button class="btn btn-o" onclick="desactiverNotifs()">Désactiver les notifications</button>':'<button class="btn btn-p" onclick="activerNotifs()">Activer les notifications</button>'}<button class="btn btn-o" onclick="definirPin()">${pinActif()?'Modifier le code PIN':'Activer un code PIN'}</button>${pinActif()?'<button class="btn btn-ghost" onclick="retirerPin()">Désactiver le code PIN</button>':''}</div></div>`);if(phase1Matches(search,['sauvegarde export import']))sections.push(`<div class="phase1-card"><h2>Sauvegarde & restauration</h2><div class="actions"><button class="btn btn-o" onclick="exporterJSON()">Exporter</button><label class="btn btn-o" style="cursor:pointer">Importer<input type="file" accept=".json" style="display:none" onchange="importerJSON(this)"></label><button class="btn btn-ghost" onclick="reinitialiser()">Réinitialiser</button></div></div>`);return sections.length?sections.join(''):`<div class="phase1-card"><div class="phase1-section-empty">Aucun réglage ne correspond à votre recherche.</div></div>`;}
function vParams(){phase1EnsureState();const s=phase1StatusReport();let content='';if(phase1SettingsSection==='company')content=phase1RenderCompanySettings();if(phase1SettingsSection==='documents')content=phase1RenderDocumentSettings();if(phase1SettingsSection==='pipeline')content=phase1RenderPipelineSettings();if(phase1SettingsSection==='security')content=phase1RenderSecuritySettings();document.getElementById('main').innerHTML=`<div class="topbar"><h1>Paramètres</h1><div class="actions"><button class="btn btn-p" onclick="phase1OpenSetup(${phase1FirstIncompleteStep()})">Finaliser l'entreprise</button></div></div><div class="phase1-settings"><aside class="phase1-settings-nav"><h2>Navigation</h2>${phase1SettingsButton('company','Mon entreprise')}${phase1SettingsButton('documents','Documents & ventes')}${phase1SettingsButton('pipeline','Pipeline & relances')}${phase1SettingsButton('security','Données & sécurité')}</aside><section class="phase1-settings-body"><div class="phase1-searchbar"><input type="search" placeholder="Rechercher un réglage" value="${esc(phase1SettingsSearch)}" oninput="phase1UpdateSettingsSearch(this.value)"><span class="phase1-note">Les changements sont enregistrés dans votre état Piloz synchronisé avec Supabase.</span></div><div class="phase1-summary"><div class="phase1-summary-card"><b>Identité</b><span>${s.identity?'Complète':'À compléter'}</span></div><div class="phase1-summary-card"><b>Fiscalité</b><span>${s.fiscal?'Complète':'À compléter'}</span></div><div class="phase1-summary-card"><b>Documents</b><span>${s.documents?'Complète':'À compléter'}</span></div><div class="phase1-summary-card"><b>Banque</b><span>${s.banking?'Complète ou différée':'À compléter'}</span></div></div>${content}</section></div>`;}
function phase1OpenSetup(step){phase1EnsureState();phase1SetupStep=Math.max(1,Math.min(step||phase1FirstIncompleteStep(),5));phase1RenderSetup();}
function phase1CloseSetup(){if(phase1NeedsSetup())return;const node=document.getElementById('phase1-setup');if(node)node.remove();}
function phase1ValidateSetupStep(step){const e=S.entreprise;if(step===1&&![e.identity.legalName,e.identity.legalForm,e.identity.siret,e.identity.addressLine1,e.identity.postalCode,e.identity.city,e.identity.country,e.identity.phone,e.identity.email].every(phase1Trim))return"Complétez tous les champs obligatoires de l'identité entreprise.";if(step===2){if(typeof e.fiscality.subjectToVat!=='boolean')return"Indiquez si l'entreprise est assujettie à la TVA.";if(e.fiscality.subjectToVat&&!phase1Trim(e.fiscality.vatNumber))return"Renseignez le numéro de TVA intracommunautaire.";if(!phase1Trim(e.fiscality.currency)||!phase1Trim(e.fiscality.language))return'Complétez la devise et la langue principale.';}if(step===3){if(![e.documents.quotePrefix,e.documents.invoicePrefix,e.documents.creditPrefix,e.documents.defaultPaymentTerms,e.documents.defaultPaymentMethod].every(phase1Trim))return'Complétez la numérotation et les conditions de paiement.';if(Number(e.documents.quoteNextNumber)<=0||Number(e.documents.invoiceNextNumber)<=0||Number(e.documents.quoteValidityDays)<=0)return'Les compteurs et la validité doivent être supérieurs à zéro.';}if(step===4){if(!Array.isArray(e.banking.acceptedPaymentMethods)||!e.banking.acceptedPaymentMethods.length)return'Sélectionnez au moins un moyen de paiement accepté.';if(!e.banking.remindLater&&![e.banking.accountHolder,e.banking.iban,e.banking.bic,e.banking.bankName].every(phase1Trim))return'Renseignez les coordonnées bancaires ou indiquez que vous les complèterez plus tard.';}return'';}
function phase1RenderSetupStep(){const e=S.entreprise;if(phase1SetupStep===1)return`<div class="phase1-card"><h2>Étape 1 — Identité de l'entreprise</h2><div class="phase1-grid"><div class="phase1-field"><label>Raison sociale *</label><input value="${esc(e.identity.legalName)}" oninput="phase1SetEntreprise('identity.legalName',this.value)"></div><div class="phase1-field"><label>Nom commercial</label><input value="${esc(e.identity.tradeName)}" oninput="phase1SetEntreprise('identity.tradeName',this.value)"></div><div class="phase1-field"><label>Forme juridique *</label><input value="${esc(e.identity.legalForm)}" oninput="phase1SetEntreprise('identity.legalForm',this.value)"></div><div class="phase1-field"><label>SIRET *</label><input value="${esc(e.identity.siret)}" oninput="phase1SetEntreprise('identity.siret',this.value.replace(/\s+/g,''))"></div><div class="phase1-field"><label>Code APE / NAF</label><input value="${esc(e.identity.apeCode)}" oninput="phase1SetEntreprise('identity.apeCode',this.value)"></div><div class="phase1-field"><label>Pays *</label><input value="${esc(e.identity.country)}" oninput="phase1SetEntreprise('identity.country',this.value)"></div><div class="phase1-field full"><label>Adresse *</label><input value="${esc(e.identity.addressLine1)}" oninput="phase1SetEntreprise('identity.addressLine1',this.value)"></div><div class="phase1-field"><label>Code postal *</label><input value="${esc(e.identity.postalCode)}" oninput="phase1SetEntreprise('identity.postalCode',this.value)"></div><div class="phase1-field"><label>Ville *</label><input value="${esc(e.identity.city)}" oninput="phase1SetEntreprise('identity.city',this.value)"></div><div class="phase1-field"><label>Téléphone *</label><input value="${esc(e.identity.phone)}" oninput="phase1SetEntreprise('identity.phone',this.value)"></div><div class="phase1-field"><label>Email professionnel *</label><input type="email" value="${esc(e.identity.email)}" oninput="phase1SetEntreprise('identity.email',this.value)"></div></div></div>`;if(phase1SetupStep===2)return`<div class="phase1-card"><h2>Étape 2 — Fiscalité</h2><div class="phase1-grid"><div class="phase1-field"><label>Assujetti à la TVA *</label><select onchange="phase1SetEntrepriseChoice('fiscality.subjectToVat',this.value)">${phase1BooleanOptions(e.fiscality.subjectToVat)}</select></div><div class="phase1-field"><label>Régime de TVA</label><input value="${esc(e.fiscality.vatRegime)}" oninput="phase1SetEntreprise('fiscality.vatRegime',this.value)"></div><div class="phase1-field"><label>N° TVA intracom</label><input value="${esc(e.fiscality.vatNumber)}" oninput="phase1SetEntreprise('fiscality.vatNumber',this.value)"></div><div class="phase1-field"><label>Taux de TVA par défaut *</label><input type="number" value="${Number(e.fiscality.defaultVatRate)||20}" oninput="phase1SetEntreprise('fiscality.defaultVatRate',Number(this.value))"></div><div class="phase1-field"><label>Devise *</label><input value="${esc(e.fiscality.currency)}" oninput="phase1SetEntreprise('fiscality.currency',this.value.toUpperCase())"></div><div class="phase1-field"><label>Langue principale *</label><select onchange="phase1SetEntreprise('fiscality.language',this.value)"><option value="fr" ${e.fiscality.language==='fr'?'selected':''}>Français</option><option value="en" ${e.fiscality.language==='en'?'selected':''}>Anglais</option></select></div></div></div>`;if(phase1SetupStep===3)return`<div class="phase1-card"><h2>Étape 3 — Documents</h2><div class="phase1-grid"><div class="phase1-field"><label>Préfixe devis *</label><input value="${esc(e.documents.quotePrefix)}" oninput="phase1SetEntreprise('documents.quotePrefix',this.value.toUpperCase())"></div><div class="phase1-field"><label>Prochain devis *</label><input type="number" value="${Number(e.documents.quoteNextNumber)||1}" oninput="phase1SetEntreprise('documents.quoteNextNumber',Number(this.value))"></div><div class="phase1-field"><label>Préfixe factures *</label><input value="${esc(e.documents.invoicePrefix)}" oninput="phase1SetEntreprise('documents.invoicePrefix',this.value.toUpperCase())"></div><div class="phase1-field"><label>Prochaine facture *</label><input type="number" value="${Number(e.documents.invoiceNextNumber)||1}" oninput="phase1SetEntreprise('documents.invoiceNextNumber',Number(this.value))"></div><div class="phase1-field"><label>Préfixe avoirs *</label><input value="${esc(e.documents.creditPrefix)}" oninput="phase1SetEntreprise('documents.creditPrefix',this.value.toUpperCase())"></div><div class="phase1-field"><label>Prochain avoir *</label><input type="number" value="${Number(e.documents.creditNextNumber)||1}" oninput="phase1SetEntreprise('documents.creditNextNumber',Number(this.value))"></div><div class="phase1-field"><label>Conditions de paiement *</label><select onchange="phase1SetEntreprise('documents.defaultPaymentTerms',this.value)">${phase1Options(phase1PaymentTerms,e.documents.defaultPaymentTerms)}</select></div><div class="phase1-field"><label>Mode de paiement préféré *</label><select onchange="phase1SetEntreprise('documents.defaultPaymentMethod',this.value)">${phase1Options(phase1PaymentMethods,e.documents.defaultPaymentMethod)}</select></div><div class="phase1-field"><label>Validité des devis *</label><input type="number" value="${Number(e.documents.quoteValidityDays)||30}" oninput="phase1SetEntreprise('documents.quoteValidityDays',Number(this.value))"></div></div></div>`;if(phase1SetupStep===4)return`<div class="phase1-card"><h2>Étape 4 — Paiements & banque</h2><div class="phase1-grid"><div class="phase1-field"><label>Titulaire du compte</label><input value="${esc(e.banking.accountHolder)}" oninput="phase1SetEntreprise('banking.accountHolder',this.value)"></div><div class="phase1-field"><label>Banque</label><input value="${esc(e.banking.bankName)}" oninput="phase1SetEntreprise('banking.bankName',this.value)"></div><div class="phase1-field"><label>IBAN</label><input value="${esc(e.banking.iban)}" oninput="phase1SetEntreprise('banking.iban',this.value.replace(/\s+/g,''))"></div><div class="phase1-field"><label>BIC</label><input value="${esc(e.banking.bic)}" oninput="phase1SetEntreprise('banking.bic',this.value.replace(/\s+/g,''))"></div><div class="phase1-field full"><label>Moyens de paiement acceptés *</label><div class="phase1-checks">${phase1PaymentMethods.map(method=>`<label class="phase1-check"><input type="checkbox" ${e.banking.acceptedPaymentMethods.includes(method)?'checked':''} onchange="phase1ToggleAcceptedMethod('${esc(method)}',this.checked)"><span>${esc(method)}</span></label>`).join('')}</div></div><div class="phase1-field full"><label>Coordonnées bancaires à compléter plus tard</label><select onchange="phase1SetEntrepriseChoice('banking.remindLater',this.value)">${phase1BooleanOptions(e.banking.remindLater)}</select></div></div><p class="phase1-note">Vous pouvez différer cette étape, mais un rappel restera visible dans les paramètres.</p></div>`;return`<div class="phase1-setup-preview"><div class="phase1-card"><h2>Résumé</h2><p><b>${esc(e.identity.legalName||'Entreprise')}</b><br>${esc(e.identity.addressLine1||'Adresse à compléter')}<br>${esc(e.identity.email||'Email à compléter')}</p><p class="phase1-note">TVA : ${e.fiscality.subjectToVat?esc(e.fiscality.vatNumber||'à compléter'):'Non assujettie'}</p></div><div class="phase1-card"><h2>Prévisualisation</h2><p>Prochain devis : <span class="phase1-mono">${esc(phase1DocNumber('D'))}</span><br>Prochaine facture : <span class="phase1-mono">${esc(phase1DocNumber('F'))}</span></p><p class="phase1-note">Paiement par défaut : ${esc(e.documents.defaultPaymentMethod)} · ${esc(e.documents.defaultPaymentTerms)}</p></div></div>`;}
function phase1RenderSetup(){if(!SES)return;let node=document.getElementById('phase1-setup');if(!node){node=document.createElement('div');node.id='phase1-setup';document.body.appendChild(node);}const progress=Math.round((phase1SetupStep/5)*100);node.className='phase1-setup';node.innerHTML=`<div class="phase1-setup-dialog"><div class="phase1-setup-head"><div><h2>Configuration initiale de l'entreprise</h2><p>Cette étape est obligatoire avant la création de devis et de factures. Vous pouvez revenir en arrière à tout moment sans perdre vos données.</p></div>${phase1NeedsSetup()?'':'<button class="btn btn-o" onclick="phase1CloseSetup()">Fermer</button>'}</div><div class="phase1-setup-progress"><div style="display:flex;justify-content:space-between;font-size:.82rem;color:var(--gris);margin-bottom:8px"><span>Étape ${phase1SetupStep} sur 5</span><span>${progress}%</span></div><div class="phase1-setup-progressbar"><i style="width:${progress}%"></i></div></div><div class="phase1-setup-body">${phase1RenderSetupStep()}</div><div class="phase1-setup-actions">${phase1SetupStep>1?'<button class="btn btn-o" onclick="phase1SetupPrev()">Retour</button>':'<span class="phase1-note">Les champs marqués * sont requis.</span>'}<button class="btn btn-p" onclick="phase1SetupNext()">${phase1SetupStep===5?'Terminer la configuration':'Continuer'}</button></div></div>`;}
function phase1SetupPrev(){phase1SetupStep=Math.max(1,phase1SetupStep-1);phase1RenderSetup();}
function phase1SetupNext(){const error=phase1ValidateSetupStep(phase1SetupStep);if(error){toast(error);return;}if(phase1SetupStep<5){phase1SetupStep+=1;S.entreprise.setup.lastStep=phase1SetupStep;sauver('Étape enregistrée');phase1RenderSetup();return;}S.entreprise.setup.completed=true;S.entreprise.setup.completedAt=new Date().toISOString();S.entreprise.setup.lastStep=5;sauver('Configuration entreprise enregistrée');phase1CloseSetup();render();}
function formSociete(){phase1SettingsSection='company';phase1OpenView('params');}
function formDoc(id,type){phase1EnsureState();const existing=id?S.factu.docs.find(doc=>doc.id===id):null;type=existing?existing.type:type;if(!existing&&phase1NeedsSetup()){phase1OpenSetup(phase1FirstIncompleteStep());return;}const delay=type==='D'?Number(S.entreprise.documents.quoteValidityDays)||30:phase1PaymentDelay();docEnCours=existing?structuredClone(existing):{type,objet:'',client:'',date:iso(AUJ()),echeance:plusJours(iso(AUJ()),delay),langue:S.entreprise.fiscality.language||'fr',devise:S.entreprise.fiscality.currency||'EUR',conditionsPaiement:S.entreprise.documents.defaultPaymentTerms||'30 jours',modePaiement:S.entreprise.documents.defaultPaymentMethod||'Virement bancaire',lignes:[{designation:'',qte:1,pu:0,tva:S.factu.tvaDefaut}],notes:'',statut:'brouillon'};formModal(`${existing?'Modifier':'Nouveau'} ${type==='D'?'devis':'facture'}${existing?' '+existing.numero:''}`,`<div class="fgrid"><div class="f full"><label>Objet / titre</label><input id="doc_title" value="${esc(docEnCours.objet||'')}"></div><div class="f"><label>Client</label><input id="doc_client" list="doc_dl" value="${esc(docEnCours.client)}"><datalist id="doc_dl">${S.clients.map(client=>`<option value="${esc(client.nom)}">`).join('')}</datalist></div><div class="f"><label>Date d'émission</label><input id="doc_date" type="date" value="${docEnCours.date}"></div><div class="f"><label>${type==='D'?'Validité jusqu’au':'Échéance de paiement'}</label><input id="doc_ech" type="date" value="${docEnCours.echeance}"></div><div class="f"><label>Conditions de paiement</label><select id="doc_terms">${phase1Options(phase1PaymentTerms,docEnCours.conditionsPaiement||S.entreprise.documents.defaultPaymentTerms)}</select></div><div class="f"><label>Mode de paiement</label><select id="doc_method">${phase1Options(phase1PaymentMethods,docEnCours.modePaiement||S.entreprise.documents.defaultPaymentMethod)}</select></div></div><div style="overflow-x:auto;margin-top:12px"><table><tr><th>Désignation</th><th>Qté</th><th>PU HT (€)</th><th>TVA %</th><th style="text-align:right">Total HT</th><th></th></tr><tbody id="doc_lignes">${docEnCours.lignes.map((line,index)=>ligneHtml(line,index)).join('')}</tbody></table></div><div class="actions" style="margin-top:8px"><button class="btn btn-o" onclick="ajouterLigne()">＋ Ajouter une ligne</button><span id="doc_tot" style="margin-left:auto;font-size:.95rem"></span></div><div class="f full" style="margin-top:10px"><label>Notes visibles sur le document</label><textarea id="doc_notes" rows="2">${esc(docEnCours.notes||'')}</textarea></div>`,()=>{docEnCours.objet=document.getElementById('doc_title').value.trim();docEnCours.client=document.getElementById('doc_client').value.trim();docEnCours.date=document.getElementById('doc_date').value;docEnCours.echeance=document.getElementById('doc_ech').value;docEnCours.conditionsPaiement=document.getElementById('doc_terms').value;docEnCours.modePaiement=document.getElementById('doc_method').value;docEnCours.notes=document.getElementById('doc_notes').value;docEnCours.lignes=docEnCours.lignes.filter(line=>line.designation||line.pu);if(!docEnCours.client){toast('Indiquez le client');return false;}if(existing){Object.assign(existing,docEnCours);}else{docEnCours.id=(S.factu.docs.reduce((max,item)=>Math.max(max,item.id||0),0))+1;docEnCours.numero=phase1DocNumber(type);phase1AdvanceDocSequence(type);S.factu.docs.push(docEnCours);}S.ventes.dueDates=phase1BuildDueDates();sauver(`${type==='D'?'Devis':'Facture'} ${docEnCours.numero} enregistré(e)`);},'Enregistrer');majTotauxForm();}
function devisVersFacture(id){phase1EnsureState();if(phase1NeedsSetup()){phase1OpenSetup(phase1FirstIncompleteStep());return;}const quote=S.factu.docs.find(doc=>doc.id===id),invoice=structuredClone(quote);invoice.id=(S.factu.docs.reduce((max,item)=>Math.max(max,item.id||0),0))+1;invoice.type='F';invoice.numero=phase1DocNumber('F');invoice.statut='brouillon';invoice.date=iso(AUJ());invoice.echeance=plusJours(iso(AUJ()),phase1PaymentDelay());invoice.ref=quote.numero;delete invoice.datePaiement;phase1AdvanceDocSequence('F');quote.statut='facturé';S.factu.docs.push(invoice);S.ventes.dueDates=phase1BuildDueDates();sauver(`Facture ${invoice.numero} créée depuis le devis ${quote.numero}`);fermer();render();voirDoc(invoice.id);}
function phase1RenderDashboard(){phase1Legacy.vAccueil();const main=document.getElementById('main');if(main)main.innerHTML=phase1PageNoticeHtml()+main.innerHTML;}
render=function(){phase1EnsureState();const fromHash=phase1ViewFromHash();if(fromHash)vue=fromHash;if(vue==='clients')vue='sales-clients';renderTabs();const foot=document.getElementById('syncfoot');if(foot)foot.innerHTML=piedSync();const map={accueil:phase1RenderDashboard,suivi:vSuivi,semaine:vSemaine,pilotage:vPilotage,mensuel:vMensuel,objectifs:vObjectifs,params:vParams,dossier:vDossier,client:vClientPage,backoffice:vBackoffice,quotes:phase1RenderQuotes,invoices:phase1RenderInvoices,contracts:phase1RenderContracts,'sales-clients':phase1Legacy.vClients,catalog:phase1RenderCatalog,'due-dates':phase1RenderDueDates,factu:phase1RenderQuotes};(map[vue]||phase1RenderDashboard)();};
normaliserEtat=function(){phase1Legacy.normaliserEtat();phase1EnsureState();};
authSyncSession=async function(opts={}){const result=await phase1Legacy.authSyncSession(opts);if(SES&&phase1NeedsSetup())phase1OpenSetup(phase1FirstIncompleteStep());return result;};
function phase1Hydrate(){if(!S){setTimeout(phase1Hydrate,120);return;}phase1EnsureState();const fromHash=phase1ViewFromHash();if(fromHash)vue=fromHash;else if(!location.hash)history.replaceState(null,'',`${location.pathname}${location.search}#${phase1HashForView(vue||'accueil')}`);render();if(SES&&phase1NeedsSetup())phase1OpenSetup(phase1FirstIncompleteStep());}
setTimeout(phase1Hydrate,40);
